ode at (0,-0.3) {$A$};
ode at (1,2.3) {$B$};
ode at (4,2.3) {$C$};
ode at (5,-0.3) {$D$};
ode at (2.5,4.3) {$E$};
ode at (2.5,2) {$M$};
ode at (2.5,-0.3) {$N$};\draw (0.3,0.2) arc (0:37:0.3);
